import { useSiteMetadata } from "../hooks/use-site-metadata"
import { socials } from "./social-icons"

interface SeoProps {
  title?: string
  pathname?: string
}

/**
 * Renders document <head> tags via Gatsby's Head API.
 * Use from a page: `export const Head: HeadFC = ({ location }) => <Seo pathname={location.pathname} />`
 */
const Seo = ({ title, pathname = "" }: SeoProps) => {
  const {
    title: defaultTitle,
    description,
    author,
    siteUrl,
    SiteImage,
  } = useSiteMetadata()

  const pageTitle = title
    ? `${title} | ${defaultTitle}`
    : `${defaultTitle} — Co-Founder & Full-Stack (MERN) Developer`
  const image = SiteImage.startsWith("http")
    ? SiteImage
    : `${siteUrl}${SiteImage}`
  const url = `${siteUrl}${pathname}`

  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "Person",
    name: defaultTitle,
    url: siteUrl,
    image,
    jobTitle: "Co-Founder & Full-Stack Developer",
    worksFor: { "@type": "Organization", name: "Humance AI Labs" },
    address: { "@type": "Country", name: "Bangladesh" },
    sameAs: socials.map((s) => s.href),
  }

  return (
    <>
      <html lang="en" />
      <title>{pageTitle}</title>
      <link rel="canonical" href={url} />
      <meta name="description" content={description} />
      <meta
        name="google-site-verification"
        content="54F3cB2mJ7mUd_1MpslYP8lMsiy9GMbjyI7AHYjeZLU"
      />

      <meta property="og:type" content="website" />
      <meta property="og:title" content={pageTitle} />
      <meta property="og:description" content={description} />
      <meta property="og:image" content={image} />
      <meta property="og:url" content={url} />

      <meta name="twitter:card" content="summary" />
      <meta name="twitter:title" content={pageTitle} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={image} />
      <meta name="twitter:creator" content={author} />

      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
    </>
  )
}

export default Seo
