import { useStaticQuery, graphql } from "gatsby"

export interface SiteMetadata {
  title: string
  description: string
  author: string
  siteUrl: string
  SiteImage: string
}

export const useSiteMetadata = (): SiteMetadata => {
  const { site } = useStaticQuery(graphql`
    query SiteMetadata {
      site {
        siteMetadata {
          title
          description
          author
          siteUrl
          SiteImage
        }
      }
    }
  `)

  return site.siteMetadata
}
