import type React from "react"
import { useEffect, useState } from "react"
import { scrollToId } from "../../../utils/scroll"

const links = [
  { id: "about", label: "About" },
  { id: "experience", label: "Experience" },
  { id: "skills", label: "Skills" },
  { id: "contact", label: "Contact" },
]

const Navbar = () => {
  const [open, setOpen] = useState(false)
  const [active, setActive] = useState("")

  // Scroll-spy: highlight the nav link for the section in view.
  useEffect(() => {
    const sections = links
      .map((l) => document.getElementById(l.id))
      .filter((el): el is HTMLElement => el !== null)

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) setActive(entry.target.id)
        })
      },
      { rootMargin: "-45% 0px -50% 0px" }
    )

    sections.forEach((el) => observer.observe(el))
    return () => observer.disconnect()
  }, [])

  const handleClick =
    (id: string) => (e: React.MouseEvent<HTMLAnchorElement>) => {
      e.preventDefault()
      scrollToId(id)
      setOpen(false)
    }

  const linkClass = (id: string) =>
    `font-mono text-sm transition-colors ${
      active === id ? "text-primary" : "text-slate-400 hover:text-white"
    }`

  return (
    <nav className="sticky top-0 z-30 border-b border-slate-800/70 bg-slate-950/80 backdrop-blur-md">
      <div className="mx-auto max-w-5xl px-5">
        <div className="flex h-16 items-center justify-between">
          <a
            href="#top"
            onClick={handleClick("top")}
            className="font-bold tracking-tight text-white transition hover:text-primary"
          >
            Sabuj Ali
          </a>

          <div className="hidden gap-7 md:flex">
            {links.map(({ id, label }) => (
              <a
                key={id}
                href={`#${id}`}
                onClick={handleClick(id)}
                className={linkClass(id)}
              >
                {label}
              </a>
            ))}
          </div>

          <button
            type="button"
            onClick={() => setOpen(!open)}
            aria-label="Toggle menu"
            aria-expanded={open}
            className="inline-flex h-10 w-10 items-center justify-center rounded-lg text-slate-300 hover:bg-slate-800 md:hidden"
          >
            <svg
              className="h-6 w-6"
              fill="none"
              stroke="currentColor"
              strokeWidth={2}
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              {open ? (
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M6 18L18 6M6 6l12 12"
                />
              ) : (
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M4 6h16M4 12h16M4 18h16"
                />
              )}
            </svg>
          </button>
        </div>

        {open && (
          <div className="flex flex-col gap-1 pb-4 md:hidden">
            {links.map(({ id, label }) => (
              <a
                key={id}
                href={`#${id}`}
                onClick={handleClick(id)}
                className={`rounded-lg px-3 py-2 hover:bg-slate-800 ${linkClass(
                  id
                )}`}
              >
                {label}
              </a>
            ))}
          </div>
        )}
      </div>
    </nav>
  )
}

export default Navbar
